def count_oscar_nominations(films):
    nominations = {
        'Edward, My Son': 1,
        'From Here to Eternity': 1,
        'The King and I': 1,
        'Heaven Knows, Mr. Allison': 1,
        'Separate Tables': 1,
        'The Sundowners': 1
    }
    return {film: nominations.get(film, 0) for film in films}

# Example usage:
films_list = ['The King and I', 'From Here to Eternity', 'Casablanca']
print(count_oscar_nominations(films_list))
# Output: {'The King and I': 1, 'From Here to Eternity': 1, 'Casablanca': 0}
